import React, { useState, useEffect } from 'react';
import TradingViewWidget from './components/TradingViewWidget';
import NewsModal from './components/NewsModal';
import SmtOverlay from './components/SmtOverlay';
import { getMarketNews } from './services/geminiService';
import { SymbolOption, Timeframe, NewsItem, SMT_PAIRS, SmtPair, TIMEFRAME_OPTIONS } from './types';

const SYMBOLS: SymbolOption[] = [
  { label: "XAUUSD", value: "OANDA:XAUUSD" },
  { label: "EURUSD", value: "OANDA:EURUSD" },
  { label: "GBPUSD", value: "OANDA:GBPUSD" },
  { label: "GBPJPY", value: "OANDA:GBPJPY" },
  { label: "BTCUSD", value: "COINBASE:BTCUSD" },
  { label: "US30", value: "BLACKBULL:US30" }
];

const LS_KEYS = {
  SYMBOL: 'goldview_selected_symbol',
  TIMEFRAMES: 'goldview_preferred_timeframes',
  THEME: 'goldview_theme'
};

const THEMES = {
  blue: {
    name: 'blue',
    bg: '#020617', // Slate 950
    candleUp: '#ffffff',
    candleDown: '#3b82f6', // Blue 500
    grid: 'rgba(30, 58, 138, 0.1)'
  },
  red: {
    name: 'red',
    bg: '#050000', // Black/Red Dark
    candleUp: '#ffffff',
    candleDown: '#ef4444', // Red 500
    grid: 'rgba(127, 29, 29, 0.1)'
  }
};

type ThemeType = 'blue' | 'red';
type SmtLayout = 'portrait' | 'vertical'; // Portrait = Stacked (Top/Bottom), Vertical = Side-by-Side (Left/Right)

const App: React.FC = () => {
  // State
  const [selectedSymbol, setSelectedSymbol] = useState<SymbolOption>(() => {
    const saved = localStorage.getItem(LS_KEYS.SYMBOL);
    return saved ? (SYMBOLS.find(s => s.value === saved) || SYMBOLS[0]) : SYMBOLS[0];
  });

  const [chartTimeframes, setChartTimeframes] = useState<Timeframe[]>(() => {
    const saved = localStorage.getItem(LS_KEYS.TIMEFRAMES);
    try {
      const parsed = JSON.parse(saved || '[]');
      if (Array.isArray(parsed) && parsed.length === 4) return parsed;
    } catch {}
    return ['W', 'D', '60', '15'];
  });

  const [theme, setTheme] = useState<ThemeType>(() => {
    return (localStorage.getItem(LS_KEYS.THEME) as ThemeType) || 'blue';
  });

  const [maximizedChartIndex, setMaximizedChartIndex] = useState<number | null>(null);

  // SMT Mode State
  const [viewMode, setViewMode] = useState<'default' | 'smt'>('default');
  const [selectedSmtPair, setSelectedSmtPair] = useState<SmtPair>(SMT_PAIRS[0]);
  const [smtTimeframe, setSmtTimeframe] = useState<Timeframe>('15');
  const [smtLayout, setSmtLayout] = useState<SmtLayout>('portrait');
  const [isSyncActive, setIsSyncActive] = useState(false);

  // Data State
  const [news, setNews] = useState<NewsItem[]>([]);
  const [loadingData, setLoadingData] = useState(false);
  const [selectedNewsItem, setSelectedNewsItem] = useState<NewsItem | null>(null);

  // Persistence
  useEffect(() => { localStorage.setItem(LS_KEYS.SYMBOL, selectedSymbol.value); }, [selectedSymbol]);
  useEffect(() => { localStorage.setItem(LS_KEYS.TIMEFRAMES, JSON.stringify(chartTimeframes)); }, [chartTimeframes]);
  useEffect(() => {
    localStorage.setItem(LS_KEYS.THEME, theme);
    const root = document.documentElement;
    if (theme === 'red') {
      root.classList.add('theme-red');
    } else {
      root.classList.remove('theme-red');
    }
  }, [theme]);

  // General Data Fetching
  useEffect(() => {
    const fetchData = async () => {
      setLoadingData(true);
      try {
        const newsData = await getMarketNews(selectedSymbol.label);
        setNews(newsData);
      } catch (e) {
        console.error("Failed to fetch data", e);
      } finally {
        setLoadingData(false);
      }
    };

    fetchData();
    // Refresh data every 5 minutes
    const interval = setInterval(fetchData, 300000); 
    return () => clearInterval(interval);
  }, [selectedSymbol]);

  const handleTimeframeChange = (index: number, newTimeframe: Timeframe) => {
    const nextTimeframes = [...chartTimeframes];
    nextTimeframes[index] = newTimeframe;
    setChartTimeframes(nextTimeframes);
  };

  const handleSmtPairChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const pair = SMT_PAIRS.find(p => p.label === e.target.value);
    if (pair) {
      setSelectedSmtPair(pair);
      // Update the main selected symbol to the first asset of the pair so the AI sidebar is relevant
      setSelectedSymbol(pair.asset1);
    }
  };

  const toggleTheme = () => {
    setTheme(prev => prev === 'blue' ? 'red' : 'blue');
  };

  return (
    <div className="h-screen w-screen flex flex-col bg-background text-textBase relative overflow-hidden font-sans transition-colors duration-500">
      {/* Background FX */}
      <div className="absolute inset-0 bg-grid pointer-events-none opacity-40 z-0"></div>
      <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-accent/10 to-transparent pointer-events-none z-0"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[500px] h-[500px] bg-accent/5 blur-[150px] rounded-full pointer-events-none"></div>

      {/* 1. Header - Ultra Slim Command Bar */}
      <header className="h-12 border-b border-border/30 bg-panel/80 backdrop-blur-md flex items-center justify-between px-4 z-20 shrink-0 shadow-[0_4px_20px_rgba(0,0,0,0.3)]">
        <div className="flex items-center gap-6">
          {/* Logo Area */}
          <div className="flex items-center gap-2 group cursor-pointer" onClick={() => setViewMode('default')}>
            <div className="w-6 h-6 bg-accent rounded flex items-center justify-center shadow-[0_0_15px_rgba(var(--color-accent),0.6)] group-hover:shadow-[0_0_25px_rgba(var(--color-glow),0.8)] transition-all duration-300 border border-glow/30">
              <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
            </div>
            <h1 className="text-sm font-black tracking-widest text-textBase uppercase font-mono">
              EG-FINANCE <span className="text-glow drop-shadow-[0_0_5px_rgba(var(--color-glow),0.8)]">FX SCANNER</span>
            </h1>
          </div>

          <div className="h-4 w-[1px] bg-border/50"></div>

          {/* Navigation / Mode Selection */}
          <div className="flex items-center gap-1">
            {viewMode === 'default' ? (
              <>
                {SYMBOLS.map((s) => (
                  <button
                    key={s.value}
                    onClick={() => setSelectedSymbol(s)}
                    className={`
                      relative px-3 py-1 rounded text-[11px] font-bold tracking-wide transition-all duration-200
                      ${selectedSymbol.value === s.value 
                        ? 'text-textBase bg-accent/20 border border-accent/30 shadow-[0_0_10px_rgba(var(--color-accent),0.2)]' 
                        : 'text-textMuted hover:text-textBase hover:bg-panel'
                      }
                    `}
                  >
                    {s.label}
                    {selectedSymbol.value === s.value && <div className="absolute bottom-0 left-0 w-full h-[1px] bg-glow shadow-[0_0_8px_rgba(var(--color-glow),0.8)]"></div>}
                  </button>
                ))}

                <div className="w-[1px] h-4 bg-border/50 mx-1"></div>

                <button
                  onClick={() => setViewMode('smt')}
                  className="px-3 py-1 rounded text-[11px] font-bold tracking-wide text-purple-400 hover:text-purple-300 hover:bg-purple-500/10 border border-transparent hover:border-purple-500/30 transition-all"
                >
                  SMT DIVERGENCE
                </button>
              </>
            ) : (
              // SMT Mode Controls
              <div className="flex items-center gap-3 animate-in fade-in slide-in-from-left-4 duration-300">
                <button
                  onClick={() => setViewMode('default')}
                  className="flex items-center gap-1 text-[11px] font-bold text-textMuted hover:text-glow transition-colors pr-2 border-r border-border/50"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                  BACK
                </button>

                <div className="flex items-center gap-2">
                  <span className="text-[10px] font-mono text-purple-400 uppercase font-bold">Pair:</span>
                  <select 
                    value={selectedSmtPair.label} 
                    onChange={handleSmtPairChange}
                    className="bg-panel/40 border border-purple-500/30 text-purple-100 text-[11px] font-bold rounded px-2 py-1 outline-none focus:border-purple-400"
                  >
                    {SMT_PAIRS.map(pair => (
                      <option key={pair.label} value={pair.label} className="bg-panel">{pair.label}</option>
                    ))}
                  </select>
                </div>

                <div className="flex items-center gap-2">
                  <span className="text-[10px] font-mono text-textMuted uppercase font-bold">TF:</span>
                  <select 
                    value={smtTimeframe}
                    onChange={(e) => setSmtTimeframe(e.target.value as Timeframe)}
                    className="bg-panel/40 border border-border/30 text-glow text-[11px] font-bold rounded px-2 py-1 outline-none focus:border-glow"
                  >
                    {TIMEFRAME_OPTIONS.map(opt => (
                      <option key={opt.value} value={opt.value} className="bg-panel">{opt.label}</option>
                    ))}
                  </select>
                </div>

                <div className="w-[1px] h-4 bg-border/50 mx-1"></div>

                {/* Layout Toggle */}
                 <div className="flex bg-panel/50 rounded border border-border/30 p-0.5">
                    <button
                        onClick={() => setSmtLayout('portrait')}
                        className={`p-1 rounded transition-colors ${smtLayout === 'portrait' ? 'bg-accent/20 text-glow' : 'text-textMuted hover:text-textBase'}`}
                        title="Portrait (Stacked)"
                    >
                        {/* Stacked Icon */}
                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 10h16M4 14h16M4 18h16" /></svg>
                    </button>
                    <button
                        onClick={() => setSmtLayout('vertical')}
                        className={`p-1 rounded transition-colors ${smtLayout === 'vertical' ? 'bg-accent/20 text-glow' : 'text-textMuted hover:text-textBase'}`}
                        title="Vertical (Side-by-Side)"
                    >
                        {/* Side by Side Icon */}
                         <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 4v16m6-16v16" /></svg>
                    </button>
                </div>

                <div className="w-[1px] h-4 bg-border/50 mx-1"></div>

                {/* Sync Toggle */}
                <button
                   onClick={() => setIsSyncActive(!isSyncActive)}
                   className={`
                      flex items-center gap-1.5 px-3 py-0.5 rounded border text-[10px] font-bold uppercase transition-all
                      ${isSyncActive 
                        ? 'bg-glow/20 border-glow text-glow shadow-[0_0_10px_rgba(var(--color-glow),0.3)]' 
                        : 'bg-transparent border-border/50 text-textMuted hover:text-textBase hover:border-textBase'
                      }
                   `}
                >
                   <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m-8-8h16" /></svg>
