                 <div className="absolute inset-0 bg-grid opacity-30 rounded-lg mix-blend-overlay"></div>
                 <svg className="w-5 h-5 text-white drop-shadow-md relative z-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>
              </div>
              <div className="flex flex-col justify-center">
                 <h1 className="text-lg font-black tracking-tighter text-white leading-none flex items-center gap-0.5">
                   EG<span className="text-accent drop-shadow-[0_0_8px_rgba(var(--color-accent),0.5)]">FINANCE</span>
                 </h1>
                 <span className="text-[9px] font-mono font-bold tracking-[0.25em] text-glow/60 uppercase group-hover:text-glow transition-colors">Pro Terminal</span>
              </div>
           </div>

           {/* Divider */}
           <div className="h-8 w-[1px] bg-gradient-to-b from-transparent via-white/10 to-transparent"></div>

           {/* Command Center / Navigation */}
           <nav className="flex items-center p-1 bg-black/20 border border-white/5 rounded-lg backdrop-blur-sm shadow-inner">
             {viewMode === 'default' ? (
                <div className="flex items-center gap-1">
                  {SYMBOLS.map((s) => (
                    <button
                      key={s.value}
                      onClick={() => setSelectedSymbol(s)}
                      className={`
                        relative px-3 py-1.5 rounded-md text-[10px] font-bold tracking-wider transition-all duration-300 font-mono uppercase group
                        ${selectedSymbol.value === s.value 
