                        </div>
                      </div>
                    </div>

                    <div className="w-[1px] h-4 bg-white/10"></div>

                    {/* SMT Tools */}
                     <div className="flex bg-black/20 rounded border border-white/5 p-0.5 ml-1">
                        <button
                            onClick={() => setSmtLayout('portrait')}
                            className={`p-1.5 rounded transition-colors ${smtLayout === 'portrait' ? 'bg-purple-500/20 text-purple-300 shadow-inner' : 'text-textMuted hover:text-textBase'}`}
                            title="Portrait"
                        >
                            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 10h16M4 14h16M4 18h16" /></svg>
                        </button>
                        <button
                            onClick={() => setSmtLayout('vertical')}
