           <nav className="flex items-center p-1 bg-black/20 border border-white/5 rounded-lg backdrop-blur-sm shadow-inner">
             {viewMode === 'default' ? (
                <div className="flex items-center gap-1">
                  {SYMBOLS.map((s) => (
                    <button
                      key={s.value}
                      onClick={() => setSelectedSymbol(s)}
                      className={`
