const TF_PRESETS = [
  { id: 'macro', label: 'MACRO (W / D / 4H / 1H)', frames: ['W', 'D', '240', '60'] as Timeframe[] },
  { id: 'intraday', label: 'INTRADAY (1H / 30m / 15m / 5m)', frames: ['60', '30', '15', '5'] as Timeframe[] }
];

