              </div>
              <div className="flex flex-col justify-center">
                 <h1 className="text-lg font-black tracking-tighter text-white leading-none flex items-center gap-0.5">
                   EG<span className="text-accent drop-shadow-[0_0_8px_rgba(var(--color-accent),0.5)]">FINANCE</span>
                 </h1>
                 <span className="text-[9px] font-mono font-bold tracking-[0.25em] text-glow/60 uppercase group-hover:text-glow transition-colors">Fx Scanner</span>
              </div>
           </div>

           {/* Divider */}
           <div className="h-8 w-[1px] bg-gradient-to-b from-transparent via-white/10 to-transparent"></div>

           {/* Command Center / Navigation */}
           <nav className="flex items-center p-1 bg-black/20 border border-white/5 rounded-lg backdrop-blur-sm shadow-inner">
             {viewMode === 'default' ? (
                <div className="flex items-center gap-1">

                  {/* Asset Selector Dropdown */}
                  <div className="flex items-center gap-2 px-2 border-r border-white/10 relative group/assets">
                      <div className="flex flex-col items-start justify-center">
                          <span className="text-[8px] font-mono text-textMuted uppercase font-bold tracking-wider mb-0.5 opacity-60">Asset</span>
                          <div className="relative">
                              <select
                                  value={selectedSymbol.value}
                                  onChange={(e) => {
                                      const s = SYMBOLS.find(sym => sym.value === e.target.value);
                                      if(s) setSelectedSymbol(s);
                                  }}
                                  className="bg-transparent text-[10px] font-bold text-white uppercase outline-none appearance-none pr-4 cursor-pointer hover:text-glow transition-colors w-[100px]"
                              >
                                  {SYMBOLS.map(s => (
                                      <option key={s.value} value={s.value} className="bg-panel text-textBase">
                                          {s.label}
                                      </option>
                                  ))}
                              </select>
                              <div className="absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none text-white/50">
                                  <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" /></svg>
                              </div>
