                                    {activePreset === 'custom' && <option value="custom" disabled className="bg-panel text-textBase">Custom View</option>}
                                </select>
                                <div className="absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none text-white/50">
                                    <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" /></svg>
                                </div>
                            </div>
                        </div>
                   </div>

                   <div className="w-[1px] h-4 bg-white/10 mx-2"></div>

                   <button
                    onClick={() => setViewMode('smt')}
                    className="flex items-center gap-2 px-3 py-1.5 rounded-md text-[10px] font-bold tracking-wider text-purple-300 hover:text-white hover:bg-purple-500/20 border border-purple-500/20 hover:border-purple-500/40 transition-all duration-300 group shadow-[0_0_10px_rgba(168,85,247,0.05)] hover:shadow-[0_0_15px_rgba(168,85,247,0.2)]"
                   >
                     <span className="w-1.5 h-1.5 rounded-full bg-purple-500 group-hover:animate-pulse shadow-[0_0_5px_#a855f7]"></span>
                     SMT
