                            : 'bg-transparent border-white/10 text-textMuted hover:text-white hover:border-white/30'
                          }
                       `}
                    >
                       <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m-8-8h16" /></svg>
                       SYNC
                    </button>
                </div>
             )}
           </nav>
        </div>

        {/* Right: System & Theme */}
        <div className="flex items-center gap-4">
           {/* Status Pill */}
           <div className="flex items-center gap-3 bg-black/20 px-3 py-1.5 rounded-full border border-white/5 backdrop-blur-md">
                <div className="flex items-center gap-2 border-r border-white/10 pr-3">
                    <div className={`w-1.5 h-1.5 rounded-full ${loadingData ? 'bg-yellow-400 animate-pulse' : 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.8)]'}`}></div>
                    <span className="text-[9px] font-mono font-bold text-textMuted uppercase tracking-wider">
                        {loadingData ? 'UPDATING' : 'ONLINE'}
