             title="Switch Theme"
           >
             <div className={`absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-500 bg-gradient-to-br ${theme === 'red' ? 'from-red-500/10' : 'from-blue-500/10'} to-transparent`}></div>
