                    {new Date().toLocaleTimeString('en-US', { hour12: false, hour: '2-digit', minute: '2-digit' })} <span className="text-textMuted text-[8px] ml-0.5">UTC</span>
                </div>
           </div>

           {/* Theme Switcher */}
           <button
             onClick={toggleTheme}
             className={`p-2 rounded-xl border transition-all duration-500 relative group overflow-hidden ${
