```tsx
import React, { useState, useRef, useEffect } from 'react';

interface Option {
  label: string;
  value: string;
}

interface GlassDropdownProps {
  value: string;
  options: Option[];
  onChange: (value: string) => void;
  className?: string; // Class for the trigger container
  triggerClassName?: string; // Class for the text itself
  minWidth?: string;
  icon?: React.ReactNode;
}

const GlassDropdown: React.FC<GlassDropdownProps> = ({ 
  value, 
  options, 
  onChange, 
  className = "",
  triggerClassName = "",
  minWidth = "120px",
  icon
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const selectedLabel = options.find((option) => option.value === value)?.label || '';

  const toggleOpen = () => setIsOpen(!isOpen);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  return (
    <div className={`relative ${className}`} ref={containerRef}>
      <button
        type="button"
        className={`inline-flex items-center justify-between w-full text-sm font-medium text-textBase bg-transparent ${triggerClassName}`}
        onClick={toggleOpen}
        style={{ minWidth }}
      >
        {selectedLabel}
        {icon}
      </button>

      {isOpen && (
        <div
          className="absolute z-50 mt-1 w-full bg-panel rounded-md shadow-lg ring-1 ring-black ring-opacity-5 focus:outline-none"
          style={{ minWidth }}
        >
          <div className="py-1" role="menu" aria-orientation="vertical" aria-labelledby="options-menu">
            {options.map((option) => (
              <button
                key={option.value}
                onClick={() => {
                  onChange(option.value);
                  setIsOpen(false);
                }}
                className="block px-4 py-2 text-sm text-textBase hover:bg-hoverPanel hover:text-glow w-full text-left"
                role="menuitem"
              >
                {option.label}
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default GlassDropdown;
```

