             ) : (
               // SMT DIVERGENCE VIEW (2 Charts)
               <div className={`flex ${smtLayout === 'portrait' ? 'flex-col' : 'flex-row'} h-full gap-1 relative`}>

                  {/* SMT SCANNER OVERLAY */}
                  <SmtOverlay 
                    analysis={null} 
