                     </div>
                     <TradingViewWidget 
                       symbol={selectedSmtPair.asset2.value}
                       interval={smtTimeframe}
                       containerId="tv_smt_2"
                       title={selectedSmtPair.asset2.label}
                       variant="minimal"
                       onTimeframeChange={(newTf) => setSmtTimeframe(newTf)}
